init"`n    "monitor_check_services"`n    "monitor_service_status"`n    "monitor_cpu"`n    "monitor_ram"`n    "monitor_disk"`n    "monitor_check_resources"`n    "monitor_network_check"`n    "monitor_external_ip"`n    "monitor_check_ssl"`n    "monitor_check_singbox_logs"`n    "monitor_check_fail2ban_logs"`n    "monitor_health_check"`n    "monitor_generate_report"`n    "module_install"`n    "module_check"`n    "module_check_services"`n    "module_check_resources"`n    "module_check_ssl"`n    "module_report"`n    "module_service_status"`n  )`n`n  local found=0`n  for func in "${required_functions[@]}"; do`n    if declare -f "$func" &>/dev/null; then`n      ((found++))`n    fi`n  done`n`n  if [[ $found -eq ${#required_functions[@]} ]]; then`n    pass "Р’СЃРµ С„СѓРЅРєС†РёРё СЃСѓС‰РµСЃС‚РІСѓСЋС‚ ($found/${#required_functions[@]})"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "РќРµ РІСЃРµ С„СѓРЅРєС†РёРё РЅР°Р№РґРµРЅС‹ ($found/${#required_functions[@]})"`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: РєРѕРЅС„РёРіСѓСЂР°С†РёРѕРЅРЅС‹Рµ РїРµСЂРµРјРµРЅРЅС‹Рµ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_config_variables() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ РєРѕРЅС„РёРіСѓСЂР°С†РёРѕРЅРЅС‹С… РїРµСЂРµРјРµРЅРЅС‹С…..."`n`n  if [[ -n "$MONITORING_LOG_DIR" ]] && [[ -n "$MONITORING_DATA_DIR" ]]; then`n    pass "РљРѕРЅС„РёРіСѓСЂР°С†РёРѕРЅРЅС‹Рµ РїРµСЂРµРјРµРЅРЅС‹Рµ СѓСЃС‚Р°РЅРѕРІР»РµРЅС‹"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "РљРѕРЅС„РёРіСѓСЂР°С†РёРѕРЅРЅС‹Рµ РїРµСЂРµРјРµРЅРЅС‹Рµ РЅРµ СѓСЃС‚Р°РЅРѕРІР»РµРЅС‹"`n  fi`n`n  # РџСЂРѕРІРµСЂСЏРµРј РїРѕСЂРѕРіРё Р°Р»РµСЂС‚РѕРІ`n  if [[ -n "$ALERT_CPU_THRESHOLD" ]] && [[ -n "$ALERT_RAM_THRESHOLD" ]] &&`n    [[ -n "$ALERT_DISK_THRESHOLD" ]] && [[ -n "$ALERT_UPTIME_THRESHOLD" ]]; then`n    pass "РџРѕСЂРѕРіРё Р°Р»РµСЂС‚РѕРІ СѓСЃС‚Р°РЅРѕРІР»РµРЅС‹"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "РџРѕСЂРѕРіРё Р°Р»РµСЂС‚РѕРІ РЅРµ СѓСЃС‚Р°РЅРѕРІР»РµРЅС‹"`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: MONITORED_SERVICES РјР°СЃСЃРёРІ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_monitored_services_array() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ РјР°СЃСЃРёРІР° MONITORED_SERVICES..."`n`n  if [[ ${#MONITORED_SERVICES[@]} -gt 0 ]]; then`n    pass "MONITORED_SERVICES РјР°СЃСЃРёРІ СЃРѕРґРµСЂР¶РёС‚ ${#MONITORED_SERVICES[@]} СЃРµСЂРІРёСЃРѕРІ"`n    ((TESTS_PASSED++)) || true`n`n    # РџСЂРѕРІРµСЂСЏРµРј РЅР°Р»РёС‡РёРµ РєР»СЋС‡РµРІС‹С… СЃРµСЂРІРёСЃРѕРІ`n    local has_marzban=false`n    local has_singbox=false`n`n    for service in "${MONITORED_SERVICES[@]}"; do`n      if [[ "$service" == "marzban" ]]; then`n        has_marzban=true`n      fi`n      if [[ "$service" == "sing-box" ]]; then`n        has_singbox=true`n      fi`n    done`n`n    if [[ "$has_marzban" == "true" ]]; then`n      pass "MONITORED_SERVICES СЃРѕРґРµСЂР¶РёС‚ marzban"`n      ((TESTS_PASSED++)) || true`n    fi`n`n    if [[ "$has_singbox" == "true" ]]; then`n      pass "MONITORED_SERVICES СЃРѕРґРµСЂР¶РёС‚ sing-box"`n      ((TESTS_PASSED++)) || true`n    fi`n  else`n    fail "MONITORED_SERVICES РјР°СЃСЃРёРІ РїСѓСЃС‚"`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: РїРѕСЂРѕРіРѕРІС‹Рµ Р·РЅР°С‡РµРЅРёСЏ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_threshold_values() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ РїРѕСЂРѕРіРѕРІС‹С… Р·РЅР°С‡РµРЅРёР№..."`n`n  # РџСЂРѕРІРµСЂСЏРµРј С‡С‚Рѕ РїРѕСЂРѕРіРё РІ СЂР°Р·СѓРјРЅС‹С… РїСЂРµРґРµР»Р°С…`n  if [[ $ALERT_CPU_THRESHOLD -ge 50 && $ALERT_CPU_THRESHOLD -le 95 ]]; then`n    pass "ALERT_CPU_THRESHOLD РІ РґРѕРїСѓСЃС‚РёРјС‹С… РїСЂРµРґРµР»Р°С… ($ALERT_CPU_THRESHOLD%)"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "ALERT_CPU_THRESHOLD РІРЅРµ РґРѕРїСѓСЃС‚РёРјС‹С… РїСЂРµРґРµР»РѕРІ ($ALERT_CPU_THRESHOLD%)"`n  fi`n`n  if [[ $ALERT_RAM_THRESHOLD -ge 50 && $ALERT_RAM_THRESHOLD -le 95 ]]; then`n    pass "ALERT_RAM_THRESHOLD РІ РґРѕРїСѓСЃС‚РёРјС‹С… РїСЂРµРґРµР»Р°С… ($ALERT_RAM_THRESHOLD%)"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "ALERT_RAM_THRESHOLD РІРЅРµ РґРѕРїСѓСЃС‚РёРјС‹С… РїСЂРµРґРµР»РѕРІ ($ALERT_RAM_THRESHOLD%)"`n  fi`n`n  if [[ $ALERT_DISK_THRESHOLD -ge 50 && $ALERT_DISK_THRESHOLD -le 95 ]]; then`n    pass "ALERT_DISK_THRESHOLD РІ РґРѕРїСѓСЃС‚РёРјС‹С… РїСЂРµРґРµР»Р°С… ($ALERT_DISK_THRESHOLD%)"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "ALERT_DISK_THRESHOLD РІРЅРµ РґРѕРїСѓСЃС‚РёРјС‹С… РїСЂРµРґРµР»РѕРІ ($ALERT_DISK_THRESHOLD%)"`n  fi`n}`n`n# в”Ђв”Ђ РћСЃРЅРѕРІРЅР°СЏ С„СѓРЅРєС†РёСЏ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`nmain() {`n  echo ""`n  echo -e "${YELLOW}в•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—${PLAIN}"`n  echo -e "${YELLOW}в•‘        CubiVeil Unit Tests - Monitoring Module       в•‘${PLAIN}"`n  echo -e "${YELLOW}в•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ${PLAIN}"`n  echo ""`n`n  info "РўРµСЃС‚РёСЂСѓРµРјС‹Р№ РјРѕРґСѓР»СЊ: $MODULE_PATH"`n  echo ""`n`n  # в”Ђв”Ђ Р—Р°РїСѓСЃРє С‚РµСЃС‚РѕРІ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n  test_file_exists`n  echo ""`n`n  test_syntax`n  echo ""`n`n  test_shebang`n  echo ""`n`n  test_monitor_init`n  echo ""`n`n  test_monitor_check_services`n  echo ""`n`n  test_monitor_service_status`n  echo ""`n`n  test_monitor_cpu`n  echo ""`n`n  test_monitor_ram`n  echo ""`n`n  test_monitor_disk`n  echo ""`n`n  test_monitor_check_resources`n  echo ""`n`n  test_monitor_network_check_mock`n  echo ""`n`n  test_monitor_external_ip`n  echo ""`n`n  test_monitor_check_ssl`n  echo ""`n`n  echo ""`n`n  test_monitor_check_singbox_logs`n  echo ""`n`n  test_monitor_check_fail2ban_logs`n  echo ""`n`n  test_monitor_health_check`n  echo ""`n`n  test_monitor_generate_report`n  echo ""`n`n  test_module_install`n  echo ""`n`n  test_module_check`n  echo ""`n`n  test_module_check_services`n  echo ""`n`n  test_module_check_resources`n  echo ""`n`n  test_module_check_ssl`n  echo ""`n`n  test_module_report`n  echo ""`n`n  test_module_service_status`n  echo ""`n`n  test_all_functions_exist`n  echo ""`n`n  test_config_variables`n  echo ""`n`n  test_monitored_services_array`n  echo ""`n`n  test_threshold_values`n  echo ""`n`n  # в”Ђв”Ђ РС‚РѕРіРё в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n  echo ""`n  echo -e "${YELLOW}в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ${PLAIN}"`n  echo -e "${GREEN}РџСЂРѕР№РґРµРЅРѕ: $TESTS_PASSED${PLAIN}"`n  if [[ $TESTS_FAILED -gt 0 ]]; then`n    echo -e "${RED}РџСЂРѕРІР°Р»РµРЅРѕ:  $TESTS_FAILED${PLAIN}"`n  fi`n  echo -e "${YELLOW}в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ${PLAIN}"`n  echo ""`n`n  if [[ $TESTS_FAILED -gt 0 ]]; then`n    echo -e "${RED}вќЊ РўРµСЃС‚С‹ РїСЂРѕРІР°Р»РµРЅС‹${PLAIN}"`n    exit 1`n  else`n    echo -e "${GREEN}вњ… Р’СЃРµ С‚РµСЃС‚С‹ РїСЂРѕР№РґРµРЅС‹${PLAIN}"`n    exit 0`n  fi`n}`n`nmain "$@"`n
